    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization service that scores sentences by word frequency
/// and returns the top-ranked ones in their original order.
/// </summary>
public partial class DocumentSummarizationService : IDocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "it", "this",
        "that", "from", "as", "be", "has", "have", "had", "not", "no",
        "do", "does", "did", "will", "would", "could", "should", "may",
        "might", "can", "its", "he", "she", "they", "we", "you", "i",
        "me", "my", "your", "his", "her", "their", "our", "been", "being",
        "if", "so", "than", "then", "about", "into", "over", "after"
    };

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scoring sentences but preserve their original order.
        var topIndices = sentenceScores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .Order()
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceBoundary().Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (!StopWords.Contains(word))
                    frequencies[word] = frequencies.GetValueOrDefault(word) + 1;
            }
        }

        return frequencies;
    }

    private static List<double> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = TokenizeWords(sentence);
            if (words.Count == 0)
            {
                scores.Add(0);
                continue;
            }

            double score = words
                .Where(w => !StopWords.Contains(w))
                .Sum(w => wordFrequencies.GetValueOrDefault(w));

            // Normalise by word count to avoid bias toward long sentences.
            scores.Add(score / words.Count);
        }

        return scores;
    }

    private static List<string> TokenizeWords(string text)
    {
        return WordToken().Matches(text)
            .Select(m => m.Value)
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\w+", RegexOptions.Compiled)]
    private static partial Regex WordToken();
}

namespace DocSummary.Services;

public interface IDocumentSummarizationService
{
    string Summarize(string documentText, int maxSentences);
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizationService _summarizer;

    public SummarizeController(IDocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

